"use strict";

/** This property values (element ids, classes etc.) might change in a XWiki update */
const XWikiConstants = Object.freeze({
  /**
   * The id of the element containing the XWiki page content
   * @type {string}
   */
  CONTENT_DIV_ID: "xwikicontent",
  /**
   * The class that is added when the CKEditor editor is opened
   * @type {string}
   */
  CKEDITOR_OPEN_CLASS: "cke_editable", // TODO: needs to be removed after the BlockNote implementation
  /**
   * The class that is added when the BlockNote editor is opened
   * @type {string}
   */
  BLOCKNOTE_OPEN_CLASS: "xwiki-blocknote-wrapper",
  /**
   * The keyboard shortcut that needs to be triggered to create a new annotation
   * @type {KeyboardEventInit}
   */
  ANNOTATE_SHORTCUT: { ctrlKey: true, keyCode: 77 } // ShortcutJS still expects the deprecated keyCode property
});
const CLASS_POPUP_OPEN = "opened";

/**
 * Debounces a function
 * @param {Function} func - A function
 * @param {number} delay - Delay time
 * @return {Function} A debounced function
 */
function debounce(func, delay) {
    let timeout;
    return function (...args) {
        clearTimeout(timeout);
        timeout = setTimeout(() => { func.apply(this, args); }, delay);
    };
}

/**
 * Inserts popup to DOM
 *  @return {HTMLElement} The popup element
 */
function addPopupToDOM() {
    const iconWrapper = document.createElement("div");
    iconWrapper.classList.add("popup-icon");

    // JavaScript API for icons (https://extensions.xwiki.org/xwiki/bin/view/Extension/Icon%20Theme%20Application#HJavaScriptAPI)
    define("annotation-popup-icons", { icons: ["comment"] });
    require(["xwiki-icon!annotation-popup-icons"], function(icons) {
        iconWrapper.appendChild(icons.comment.render());
    });

    const popup = document.createElement("div");
    popup.id = "annotation-popup";
    popup.appendChild(iconWrapper);

    document.body.appendChild(popup);
    return popup;
}

/**
 * Close the popup
 * @param {HTMLElement} popup - The popup element
 */
const closePopup = (popup) => { popup.classList.remove(CLASS_POPUP_OPEN) };

/**
 * Displays the popup near the selected text range
 * @param {HTMLElement} popup - The popup element
 * @param {Selection} selection - A selection
 */
function openPopup(popup, selection) {
    // use rect of last last line/element, important for correct positioning in multi-line selections
    const rects = selection.getRangeAt(0).getClientRects();
    const rect = rects[rects.length - 1];

    popup.style.top = (rect.top + window.scrollY - popup.offsetHeight - 4) + "px"; // 4px over selection so that it is not "attached"
    popup.style.left = (rect.left + window.scrollX + rect.width - (popup.offsetWidth / 2)) + "px";
    popup.classList.add(CLASS_POPUP_OPEN);

    // close popup on click away
    const onClickAway = debounce((event) => {
        // Check if the click was within the bounds of the original text selection
        const isClickInsideSelection = rect.left <= event.clientX &&
                                       event.clientX <= rect.right &&
                                       rect.top <= event.clientY &&
                                       event.clientY <= rect.bottom;

        if (!popup.contains(event.target) && !isClickInsideSelection) {
            closePopup(popup);
            document.removeEventListener("click", onClickAway);
        }
    }, 60);
    document.addEventListener("click", onClickAway);

    // close popup when making a new selection
    const onNewSelect = () => {
        closePopup(popup);
        document.removeEventListener("selectionchange", onNewSelect);
    };
    document.addEventListener("selectionchange", onNewSelect);
}

/**
 * Register event listeners
 * @param {HTMLElement} wikiContent - The xwikicontent div container
 * @param {number} popup - The popup element
 */
function registerListeners(wikiContent, popup) {
    /**
     * Checks the current selection and opens the popup
     */
    function onSelectionChange() {
        const selection = window.getSelection();
        if (!selection || !selection.toString() || !wikiContent.contains(selection.anchorNode)) {
            return;
        }

        openPopup(popup, selection);
    }

    /**
     * Disables popup when editor is opened
     * @param {MutationRecord[]} mutations - The xwikicontent div container
     */
    function onClassChange(mutations) {
        for (const mutation of mutations) {
            if (mutation.type !== "attributes" || mutation.attributeName !== "class") {
                continue;
            }

            const newClassList = mutation.target.classList;
            const isEditorOpen = newClassList.contains(XWikiConstants.CKEDITOR_OPEN_CLASS) || newClassList.contains(XWikiConstants.BLOCKNOTE_OPEN_CLASS);
            if (isEditorOpen) {
                document.removeEventListener("selectionchange", listener);
            } else {
                document.addEventListener("selectionchange", listener);
            }
        }
    }

    // selection listener
    const selectionListener = debounce(onSelectionChange, 800);
    document.addEventListener("selectionchange", selectionListener);

    // disable annotation popup inside editor
    const classObserver = new MutationObserver(onClassChange);
    classObserver.observe(wikiContent, { attributes: true, attributeFilter: ["class"] });

    // popup listeners
    popup.addEventListener("click", () => {
        closePopup(popup);
        document.dispatchEvent(new KeyboardEvent("keydown", XWikiConstants.ANNOTATE_SHORTCUT));
    });
    popup.addEventListener("pointerdown", (event) => { event.preventDefault(); }); // prevent losing focus (the selection) when clicking on popup edges
}

document.addEventListener("DOMContentLoaded", () => {
    // Load the annotations only in view mode, if the document content is displayed
    const wikiContent = document.getElementById(XWikiConstants.CONTENT_DIV_ID);
    if (XWiki.contextaction != "view" || !wikiContent) {
        return;
    }

    const popup = addPopupToDOM();
    registerListeners(wikiContent, popup);
});

#annotation-popup {
  position: absolute;
  background-color: #fff;
  padding: 4px;
  border-radius: 4px;
  box-shadow: 0 1.65px 3px rgba(0, 0, 0, .2);
  visibility: hidden;
  opacity: 0;
  transition: opacity .2s ease-in;

  .opened {
    visibility: visible;
    opacity: 1;
  }

  .popup-icon {
    padding: 4px 5.25px;
    border-radius: 4px;
    cursor: pointer;
    transition: background-color .1s ease-in;

    &:hover {
      background-color: rgba(9, 30, 66, .13);
    }
  }
}
